package annotation

import (
	"os"
	"path/filepath"
	"strings"
	"testing"
)

func TestCheckThink_WithThink(t *testing.T) {
	dir := t.TempDir()
	path := filepath.Join(dir, "ok.go")
	src := `package example

// CreateUser 建立使用者
// @ai:generated by=claude-opus-4-6 date=2026-06-18
func CreateUser() {
	//@ai:think intent=建立使用者流程
	println("ok")
}
`
	if err := os.WriteFile(path, []byte(src), 0644); err != nil {
		t.Fatal(err)
	}

	report, err := CheckThink(path)
	if err != nil {
		t.Fatal(err)
	}
	if report.Scanned != 1 {
		t.Errorf("scanned = %d, want 1", report.Scanned)
	}
	if len(report.Missing) != 0 {
		t.Errorf("missing = %d, want 0", len(report.Missing))
	}
}

