func TestCheckThink_MissingThink(t *testing.T) {
	dir := t.TempDir()
	path := filepath.Join(dir, "missing.go")
	src := `package example

// CreateUser 建立使用者
// @ai:generated by=claude-opus-4-6 date=2026-06-18
func CreateUser() {
	println("no think here")
}

// DeleteUser 刪除使用者
// @ai:generated by=claude-opus-4-6 date=2026-06-18
func DeleteUser() {
	println("also missing")
}
`
	if err := os.WriteFile(path, []byte(src), 0644); err != nil {
		t.Fatal(err)
	}

	report, err := CheckThink(path)
	if err != nil {
		t.Fatal(err)
	}
	if report.Scanned != 2 {
		t.Errorf("scanned = %d, want 2", report.Scanned)
	}
	if len(report.Missing) != 2 {
		t.Fatalf("missing = %d, want 2", len(report.Missing))
	}
	if report.Missing[0].Name != "CreateUser" {
		t.Errorf("missing[0].Name = %q, want CreateUser", report.Missing[0].Name)
	}
	if report.Missing[1].Name != "DeleteUser" {
		t.Errorf("missing[1].Name = %q, want DeleteUser", report.Missing[1].Name)
	}
}

